using Microsoft.EntityFrameworkCore;

// Cosmos DB project context — demonstrates two EF Core 9 breaking changes.
class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=PLACEHOLDER",
            "CatalogDb",
            // EF9 breaking change: synchronous Cosmos DB I/O now throws
            // InvalidOperationException by default. If you cannot migrate to
            // async calls immediately, opt in explicitly:
            cosmos => cosmos.AllowSynchronousIO());
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");
            b.HasPartitionKey(p => p.Category);

            // EF9 breaking change: the default discriminator property was
            // renamed from "Discriminator" to "$type". Existing documents
            // already store "Discriminator", so we must keep the old name
            // to avoid data-shape mismatches at runtime.
            b.HasDiscriminator<string>("Discriminator");
        });
    }

    // Example: migrating a synchronous query to async (preferred over AllowSynchronousIO).
    // BEFORE (EF8 — worked but was sync-over-async internally):
    //   var items = db.Products.Where(p => p.Price > 10).ToList();
    //
    // AFTER (EF9 — use async to avoid the sync I/O exception):
    //   var items = await db.Products.Where(p => p.Price > 10).ToListAsync();
}

class Product
{
    public string Id { get; set; } = null!;
    public string Category { get; set; } = null!;
    public decimal Price { get; set; }
}

